  "objectives": [],
  "questionProse": [
    "आपको `<dialog>` एलिमेंट का उपयोग क्यों करना चाहिए?"
  ],
  "hintsProse": [],
  "explanationProse": [
    "`<dialog>` एलिमेंट पॉप-अप या मॉडल के लिए उपयोग किया जाता है, और यह इन इंटरैक्शन के लिए सिमैंटिक मार्कअप, विस्तारित CSS, और एक नेटिव API प्रदान करता है।\n\n    मॉडल डायलॉग के लिए `.showModal()` या गैर-मॉडल डायलॉग के लिए `.show()` के साथ इसे खोलने के लिए JavaScript का उपयोग करें, और इसे `.close()` या `method=\"dialog\"` का उपयोग करके फॉर्म सबमिशन के साथ बंद करें।"
  ]
}
